mapper.select:
SELECT ID, EDU_ID, WORDS_ID
FROM TBL_EDU_WORD_MAP
WHERE EDU_ID = #{eduId}
    AND WORDS_ID = #{wordsId}

SELECT COUNT(*)
FROM TBL_EDU_WORD_MAP
WHERE EDU_ID = #{eduId}

mapper.update:
UPDATE TBL_EDU_WORD_MAP
SET EDU_ID = #{eduId},
    WORDS_ID = #{wordsId}
WHERE ID = #{id}

mapper.delete:
DELETE FROM TBL_EDU_WORD_MAP
WHERE EDU_ID = #{eduId}
  AND WORDS_ID = #{wordsId}
